// mathUtils.ts
// 1. Named Exports
export function add(a: number, b: number): number {
  return a + b;
}
export function subtract(a: number, b: number): number {
  return a - b;
}

// 2. Default Export
export default function multiply(a: number, b: number): number {
  return a * b;
}

// main.ts
// 3. Named və Default Import
import { add, subtract } from "./mathUtils";
import multiply from "./mathUtils";
console.log(add(5, 3)); // Çıxış: 8
console.log(subtract(5, 3)); // Çıxış: 2
console.log(multiply(5, 3)); // Çıxış: 15

// 4. Modul ilə Interfeys və Sinif
export interface User {
  name: string;
  age: number;
}
export class UserProfile {
  constructor(public user: User) {}
  display(): string {
    return `Name: ${this.user.name}, Age: ${this.user.age}`;
  }
}

// main.ts (davamı)
import { User, UserProfile } from "./mathUtils";
const user: User = { name: "Alice", age: 30 };
const profile = new UserProfile(user);
console.log(profile.display()); // Çıxış: Name: Alice, Age: 30

// 5. Modul Alias və Hamısını Import
// import * as Math from "./mathUtils";
console.log(Math.add(10, 5)); // Çıxış: 15

// product.ts
interface Product {
  id: string;
  name: string;
  price: number;
}
export function addProduct(products: Product[], product: Product): Product[] {
  return [...products, product];
}
export function getTotalPrice(products: Product[]): number {
  return products.reduce((total, p) => total + p.price, 0);
}

// main.ts
import { addProduct, getTotalPrice, Product } from "./product";
const products: Product[] = [];
const laptop: Product = { id: "P001", name: "Laptop", price: 999 };
const updatedProducts = addProduct(products, laptop);
console.log(getTotalPrice(updatedProducts)); // Çıxış: 999

// user.ts
export function greet(name: string): string {
  return `Welcome, ${name}!`;
}

// main.ts (davamı)
import { greet } from "./user";
console.log(greet("Alice")); // Çıxış: Welcome, Alice!

// Modul nümunəsi
// math.ts
export function log(message: string): void {
  console.log(message);
}

// main.ts
import { log } from "./math";
log("Module log"); // Çıxış: Module log

// Eyni funksionallıq namespace ilə
namespace Logger {
  export function log(message: string): void {
    console.log(message);
  }
}
Logger.log("Namespace log"); // Çıxış: Namespace log

